@flyc.kernel
def amdgpu_gemm_double_buffer(
    A: fx.Tensor,
    B: fx.Tensor,
    C: fx.Tensor,
    M: fx.Int32,
    N: fx.Int32,
    K: fx.Int32,
    stride_a: fx.Int32,
    stride_b: fx.Int32,
    stride_c: fx.Int32,
):
    bid = gpu.block_idx.x
    tid = gpu.thread_idx.x

    smem = SmemAllocator()
    smem_a = smem.alloc((16, 16), fx.Float32)
    smem_b = smem.alloc((16, 16), fx.Float32)

    warp_id = tid // WarpSize
    lane_id = tid % WarpSize

    def mfma_instr(a, b, c):
        return rocdl.mfma_f32_16x16x16_bf16(a, b, c)

    def load_a():
        return buffer_ops.load(A, (bid * 16, tid))

    def load_b():
        return buffer_ops.load(B, (tid, bid * 16))

    def store_c(c):
        return buffer_ops.store(C, (bid * 16, tid), c)

    def main_loop():
        a = load_a()
        b = load_b()
        c = mfma_instr(a, b, fx.Float32(0))
        store_c(c)

    main_loop()

