@flyc.kernel
def gemm_kernel(A, B, C):
  tile_shape = fx.make_layout(16, 16)
  smem = fx.SmemAllocator()
  A_local = smem.alloc(tile_shape, fx.float32)
  B_local = smem.alloc(tile_shape, fx.float32)
  C_local = smem.alloc(tile_shape, fx.float32)

  for ii in fx.thread_idx.x.range(0, tile_shape[0]):
    for jj in fx.thread_idx.y.range(0, tile_shape[1]):
      A_local[ii, jj] = A[ii, jj]
      B_local[ii, jj] = B[ii, jj]
