@flyc.kernel
def rmsnorm_kernel(
    A: fx.Tensor,
    B: fx.Tensor,
    C: fx.Tensor,
    N: fx.Constexpr[int],
    S: fx.Constexpr[int],
):
    bid = fx.block_idx.x
    tid = fx.thread_idx.x
    smem = SmemAllocator()
    tileA = smem.alloc((fx.constexpr(16), fx.constexpr(16)), fx.float32)
    tileB = smem.alloc((fx.constexpr(16), fx.constexpr(16)), fx.float32)
    tileC = smem.alloc((fx.constexpr(16), fx.constexpr(16)), fx.float32)

    @flyc.stage
    def load_A():
        for i in range(16):
            for j in range(16):
                tileA[i, j] = A[bid * 16 + i, tid * 16 + j]

    @flyc.stage
    def load_B():
        for i in range(16):
            for j in range(16):
                tileB[i, j] = B[bid * 16 + i, tid * 16 + j]

    @flyc.stage
    def compute_C():
        for i in range(16):
            for j in range(16):
                tileC[i, j] = tileA[i, j] * tileB[i, j]

    @flyc.stage
    def store_C():
        for i in range(16):
            for j in range(16):
                C[bid * 16 + i, tid * 16 + j] = tileC[i, j]

    pipeline = [
        load_A,
        load_B,
        compute_C,
        store_C,
    ]
    flyc.emit(pipeline)
    return C

