def mfma_instruction(
    c: fx.Tensor,
    a: fx.Tensor,
    b: fx.Tensor,
    c_clobber: Optional[fx.Tensor] = None,
):
    if c_clobber is not None:
        c = c_clobber
    return rocdl.mfma_f32_16x16x4f32(a, b, c, 0, 0, 0)


def mfma_sub_tiles(
