@flyc.kernel
def mla_kernel(
    A: fx.Tensor,
    B: fx.Tensor,
    C: fx.Tensor,
    N: fx.Tensor,
    M: fx.Tensor,
    K: fx.Tensor,
):
    tid = gpu.thread_idx.x
    bid = gpu.block_idx.x
    num_tiles = N // BLOCK_N
    num_sub_tiles = get_num_sub_tiles(BLOCK_N)

    smem_allocator = SmemAllocator()
    a_smem = smem_allocator.allocate((BLOCK_M, BLOCK_K), dtype=A.dtype)
    b_smem = smem_allocator.allocate((BLOCK_K, BLOCK_N), dtype=B.dtype)
    c_smem = smem_allocator.allocate((BLOCK_M, BLOCK_N), dtype=C.dtype)

    # Pipeline stages
    for stage in range(PIPE_STAGES):
        # Load A and B into shared memory
        buffer_ops.copy(a_smem, A, (bid, stage * BLOCK_K))
        buffer_ops.copy(b_smem, B, (stage * BLOCK_K, bid))

        # MFMA computation
        for sub_tile in range(num_sub_tiles):
            c_sub = c_smem[tid % MFMA_N, sub_tile * MFMA_N + tid // MFMA_N]
            a_sub = a_smem[tid % MFMA_N, sub_tile * MFMA_N + tid // MFMA_N]
            b_sub = b_smem[sub_tile * MFMA_N + tid % MFMA_N, tid // MFMA_N]
            mfma_sub_tile(c_sub, a_sub, b_sub)

    # Store C back to global memory
    buffer_ops.copy(C, c_smem, (bid, 0))


@flyc.jit
def mla_launcher(A, B, C, N, M, K):
    block_dim = (BLOCK_M, 1, 1)
    grid_dim = (N // BLOCK_N, 1, 1)
    mla_kernel[A.dtype, B.dtype, C.dtype](A, B, C, N, M, K, grid=grid_dim, block=block_dim)

