@flyc.jit
def _softmax_kernel(
    input: fx.Tensor,
    output: fx.Tensor,
    N: fx.Int32,
    C: fx.Int32,
    K: fx.Int32,
):
    tid = fx.thread_idx.x
    bid = fx.block_idx.x

    def softmax_single_tile(i, j):
        start = j * 64 + tid
        end = start + 64
        max_val = fx.float32(-1e30)
        for k in fx.make_range(start, end):
            val = input[i, k]
            if val > max_val:
                max_val = val

        exp_sum = fx.float32(0)
        for k in fx.make_range(start, end):
            exp_val = fx.exp(input[i, k] - max_val)
            exp_sum += exp_val

        for k in fx.make_range(start, end):
            output[i, k] = fx.exp(input[i, k] - max_val) / exp_sum

    for i in fx.make_range(bid * N, (bid + 1) * N):
        for j in fx.make_range(0, C // 64):
            softmax_single_tile(i, j)

    return fx.void()


