import flydsl.compiler as flyc
import flydsl.expr as fx
from flydsl.expr import arith
from flydsl.expr import buffer_ops
from flydsl.expr import const_expr
from flydsl.expr import rocdl
from flydsl.expr.typing import AccessPtr
from flydsl.expr.typing import Array
from flydsl.expr.typing import T
from flydsl.runtime.device import get_rocm_arch

@flyc.jit
def _get_warp_id():
    # Assuming the thread block size is 256 (1 wavefront)
    return arith.div(rocdl.lane_id(), const_expr.ConstExpr(64))

@flyc.jit
def _get_lane_id():
    return arith.mod(rocdl.lane_id(), const_expr.ConstExpr(64))

@flyc.jit
def _shfl_xor_sync(value, lane_mask):
    return rocdl.ds_swizzle_b32(value, lane_mask)

@flyc.jit
def _reduce_warp_sum(value, warp_id, lane_id):
    for i in range(32, 0, -1):
        value += _shfl_xor_sync(value, const_expr.ConstExpr(i))
    return value

@flyc.jit
def _block_reduce_sum(value, warp_id, lane_id):
    block_reduce_buffer = fx.alloc(const_expr.ConstExpr(64), fx.f32)
    fx.store(block_reduce_buffer[lane_id], value, const_expr.ConstExpr(1))
    fx.sync.wave()
    if lane_id == 0:
        fx.store(block_reduce_buffer[0], _reduce_warp_sum(fx.load(block_reduce_buffer[0], const_expr.ConstExpr(1)), warp_id, lane_id), const_expr.ConstExpr(1))
    fx.sync.wave()
    return fx.load(block_reduce_buffer[0], const_expr.ConstExpr(1))

@flyc.kernel
def quant_kernel(
    input_data: AccessPtr[T.fxfloat32],
    scale: AccessPtr[T.fxfloat32],
    quantized_data: AccessPtr[T.fxint8],
    N: fx.Int32,
):
    # Get the thread index
    tid = rocdl.lane_id()

    # Calculate the warp ID and lane ID
    warp_id = _get_warp_id()
    lane_id = _get_lane_id()

    # Initialize the accumulator
    acc = fx.make_const(0.0, fx.f32)

    # Loop over the elements
    for i in fx.make_range(N):
        # Load the input data
        input = buffer_ops.buffer_load(input_data, fx.make_const(i, fx.int32), fx.f32)

        # Scale the input
        scaled = input * buffer_ops.buffer_load(scale, fx.make_const(0, fx.int32), fx.f32)

        # Accumulate the scaled value
        acc += scaled

    # Reduce the accumulator across the warp
    reduced = _reduce_warp_sum(acc, warp_id, lane_id)

    # Reduce the accumulator across the block
    final_reduced = _block_reduce_sum(reduced, warp_id, lane_id)

    # Quantize the final reduced value
    quantized = arith.round(final_reduced)

    # Store the quantized value
    buffer_ops.buffer_store(quantized_data, quantized, fx.make_const(0, fx.int32))

