import torch
import flydsl.compiler as flyc
import flydsl.expr as fx
from flydsl.expr import arith, buffer_ops, const_expr, gpu, range_constexpr, rocdl
from flydsl.expr.typing import Array, F16, F32, Index, Tensor
from flydsl.utils.smem_allocator import SmemAllocator


@flyc.jit
def load_qkv(qkv: Tensor, qkv_ptr: fx.DeviceArray, qkv_meta: Tensor):
    # Load qkv from global memory
    qkv_block = buffer_ops.tensor_load(qkv_ptr, qkv_meta)
    return qkv_block


@flyc.jit
def compute_attn(qk: Array[F32], q: Array[F16], k: Array[F16]):
    # Compute qk = q @ k.T
    for i in range_constexpr(q.shape[0]):
        for j in range_constexpr(k.shape[1]):
            qk[i, j] = 0.0
            for k in range_constexpr(q.shape[1]):
                qk[i, j] += q[i, k] * k[j, k]


@flyc.jit
def softmax(qk: Array[F32], softmax_out: Array[F32]):
    # Softmax over qk
    max_val = arith.max(qk)
    exp_sum = 0.0
    for i in range_constexpr(qk.shape[0]):
        exp_sum += rocdl.exp(qk[i] - max_val)
    for i in range_constexpr(qk.shape[0]):
        softmax_out[i] = rocdl.exp(qk[i] - max_val) / exp_sum


@flyc.jit
def apply_mask(softmax_out: Array[F32], mask: Array[F32]):
    # Apply mask
    for i in range_constexpr(softmax_out.shape[0]):
        softmax_out[i] *= mask[i]


@flyc.jit
def matmul_v(softmax_out: Array[F32], v: Array[F16], attn_out: Array[F32]):
    # Compute attn_out = softmax_out @ v
    for i in range_constexpr(softmax_out.shape[0]):
        for j in range_constexpr(v.shape[1]):
            attn_out[i, j] = 0.0
            for k in range_constexpr(v.shape[0]):
                attn_out[i, j] += softmax_out[i] * v[k, j]


@flyc.jit
def write_output(attn_out: Array[F32], output_ptr: fx.DeviceArray):
    # Write attn_out to global memory
    buffer_ops.tensor_store(output_ptr, attn_out)


@flyc.kernel
def flash_attn_kernel(
    qkv_ptr: fx.DeviceArray,
    qkv_meta: Tensor,
    mask: Array[F32],
    output_ptr: fx.DeviceArray,
):
    bid = gpu.block_idx.x
    tid = gpu.thread_idx.x

    smem = SmemAllocator()
    qk_smem = smem.alloc([128, 128], F32)
    v_smem = smem.alloc([128, 128], F16)
    softmax_out_smem = smem.alloc([128], F32)

    qkv_block = load_qkv(qkv_ptr, qkv_meta)
    q = qkv_block[0]
    k = qkv_block[1]
    v = qkv_block[2]

    compute_attn(qk_smem, q, k)
    softmax(qk_smem, softmax_out_smem)
    apply_mask(softmax_out_smem, mask)
    matmul_v(softmax_out_smem, v_smem, qk_smem)
    write_output(qk_smem, output_ptr)


